import{_ as a,o as r,c as e,a0 as o}from"./chunks/framework.AQcSKqPn.js";const c=JSON.parse('{"title":"AI情报日报 2026-07-13","description":"","frontmatter":{"type":"page","title":"AI情报日报 2026-07-13","tags":["ai","daily-report","情报"],"created":"2026-07-13T00:00:00.000Z"},"headers":[],"relativePath":"daily/ai-report-2026-07-13.md","filePath":"daily/ai-report-2026-07-13.md","lastUpdated":1783908220000}'),d={name:"daily/ai-report-2026-07-13.md"};function l(i,t,h,n,s,u){return r(),e("div",null,[...t[0]||(t[0]=[o('<h1 id="ai情报日报-2026-07-13" tabindex="-1">AI情报日报 2026-07-13 <a class="header-anchor" href="#ai情报日报-2026-07-13" aria-label="Permalink to &quot;AI情报日报 2026-07-13&quot;">​</a></h1><h2 id="ai-hot-精选" tabindex="-1">AI HOT 精选 <a class="header-anchor" href="#ai-hot-精选" aria-label="Permalink to &quot;AI HOT 精选&quot;">​</a></h2><h3 id="模型发布-更新" tabindex="-1">模型发布/更新 <a class="header-anchor" href="#模型发布-更新" aria-label="Permalink to &quot;模型发布/更新&quot;">​</a></h3><h4 id="_1-腾讯混元发布hy3模型-295b参数moe架构-agent向llm定位" tabindex="-1">1. 腾讯混元发布Hy3模型：295B参数MoE架构，Agent向LLM定位 <a class="header-anchor" href="#_1-腾讯混元发布hy3模型-295b参数moe架构-agent向llm定位" aria-label="Permalink to &quot;1. 腾讯混元发布Hy3模型：295B参数MoE架构，Agent向LLM定位&quot;">​</a></h4><p>腾讯混元团队发布Hy3模型，采用295B总参数、21B激活参数的MoE架构，推理效率可打平参数规模2-5倍的旗舰模型。Hy3定位为Agent向LLM，内部WorkBuddy任务成功率从72%提升至90%，耗时降低34%，幻觉和常识错误持续下降。已集成至微信服务10亿+用户。</p><ul><li>来源：<a href="https://x.com/AYi_AInotes/status/2076341952023310580" target="_blank" rel="noreferrer">X：阿易 AI Notes</a></li></ul><hr><h3 id="产品发布-更新" tabindex="-1">产品发布/更新 <a class="header-anchor" href="#产品发布-更新" aria-label="Permalink to &quot;产品发布/更新&quot;">​</a></h3><h4 id="_2-mesh-llm-在iroh上进行分布式ai计算" tabindex="-1">2. Mesh LLM：在iroh上进行分布式AI计算 <a class="header-anchor" href="#_2-mesh-llm-在iroh上进行分布式ai计算" aria-label="Permalink to &quot;2. Mesh LLM：在iroh上进行分布式AI计算&quot;">​</a></h4><p>开源项目，可将用户多台机器的GPU和内存池化，对外暴露兼容OpenAI的API。通过iroh网络库实现点对点连接，无需中央服务器。支持从5亿参数到235B MoE巨模型，软件体积仅约18MB。</p><ul><li>来源：<a href="https://www.iroh.computer/blog/mesh-llm" target="_blank" rel="noreferrer">iroh.computer</a></li></ul><h4 id="_3-codex与chatgpt-work多项更新-取消5小时限制" tabindex="-1">3. Codex与ChatGPT Work多项更新：取消5小时限制 <a class="header-anchor" href="#_3-codex与chatgpt-work多项更新-取消5小时限制" aria-label="Permalink to &quot;3. Codex与ChatGPT Work多项更新：取消5小时限制&quot;">​</a></h4><p>过去48小时内完成三项重要更新：暂时取消所有Plus/Business/Pro计划的5小时使用限制；推出变更使GPT 5.6 Sol整体更高效；已达到600万活跃用户。</p><ul><li>来源：<a href="https://x.com/thsottiaux/status/2076365965915467978" target="_blank" rel="noreferrer">X：Tibo</a></li></ul><h4 id="_4-mindwalk-在代码库3d地图上回放编码代理会话" tabindex="-1">4. Mindwalk：在代码库3D地图上回放编码代理会话 <a class="header-anchor" href="#_4-mindwalk-在代码库3d地图上回放编码代理会话" aria-label="Permalink to &quot;4. Mindwalk：在代码库3D地图上回放编码代理会话&quot;">​</a></h4><p>可视化工具，可将Claude Code和Codex的会话日志在代码库的3D地图上回放。文件触达状态分为未访问、已查看、已读取、已编辑四种颜色标记。单Go二进制文件运行，所有数据完全本地处理。</p><ul><li>来源：<a href="https://github.com/cosmtrek/mindwalk" target="_blank" rel="noreferrer">GitHub</a></li></ul><hr><h3 id="行业动态" tabindex="-1">行业动态 <a class="header-anchor" href="#行业动态" aria-label="Permalink to &quot;行业动态&quot;">​</a></h3><h4 id="_5-苹果起诉openai挖角窃密" tabindex="-1">5. 苹果起诉OpenAI挖角窃密 <a class="header-anchor" href="#_5-苹果起诉openai挖角窃密" aria-label="Permalink to &quot;5. 苹果起诉OpenAI挖角窃密&quot;">​</a></h4><p>苹果在美国起诉OpenAI，指控其挖角400名员工、窃取工程机和机密文件。分析师认为即使指控未证实，OpenAI的硬件计划仍可能受拖累，双方本就脆弱的合作关系将进一步削弱。</p><ul><li>来源：<a href="https://www.ithome.com/0/975/666.htm" target="_blank" rel="noreferrer">IT之家</a></li></ul><hr><h3 id="论文研究" tabindex="-1">论文研究 <a class="header-anchor" href="#论文研究" aria-label="Permalink to &quot;论文研究&quot;">​</a></h3><h4 id="_6-openai-gpt-5-6-sol-ultra一小时证明50年图论猜想" tabindex="-1">6. OpenAI GPT-5.6 Sol Ultra一小时证明50年图论猜想 <a class="header-anchor" href="#_6-openai-gpt-5-6-sol-ultra一小时证明50年图论猜想" aria-label="Permalink to &quot;6. OpenAI GPT-5.6 Sol Ultra一小时证明50年图论猜想&quot;">​</a></h4><p>OpenAI GPT-5.6 Sol Ultra模型在不到一小时内生成图论难题&quot;循环双覆盖猜想&quot;的完整证明，该猜想由George Szekeres和Paul Seymour于1970年代提出，悬而未决超过50年。模型调用64个并行子智能体及对抗智能体，若通过验证将是LLM首次独立解决维基百科&quot;未解决数学问题&quot;列表中的难题。</p><ul><li>来源：<a href="https://www.ithome.com/0/975/646.htm" target="_blank" rel="noreferrer">IT之家</a></li></ul><hr><h3 id="技巧与观点" tabindex="-1">技巧与观点 <a class="header-anchor" href="#技巧与观点" aria-label="Permalink to &quot;技巧与观点&quot;">​</a></h3><h4 id="_7-纳德拉提出-反向信息悖论-企业使用ai时需保护自身知识" tabindex="-1">7. 纳德拉提出&quot;反向信息悖论&quot;：企业使用AI时需保护自身知识 <a class="header-anchor" href="#_7-纳德拉提出-反向信息悖论-企业使用ai时需保护自身知识" aria-label="Permalink to &quot;7. 纳德拉提出&quot;反向信息悖论&quot;：企业使用AI时需保护自身知识&quot;">​</a></h4><p>微软CEO萨提亚·纳德拉指出：AI时代，企业为使用AI支付金钱，同时必须暴露专有知识（提示词、工具使用、纠正反馈等），这些&quot;智力废气&quot;被模型学习。呼吁企业拥有私有评估、保留组织记忆所有权，并主张企业应有权使用模型输出微调或训练自有模型。</p><ul><li>来源：<a href="https://x.com/satyanadella/status/2076323181154230284" target="_blank" rel="noreferrer">X：Satya Nadella</a></li></ul><h4 id="_8-xai-grok-build-cli网络流量分析-上传仓库全部文件及git历史" tabindex="-1">8. xAI Grok Build CLI网络流量分析：上传仓库全部文件及git历史 <a class="header-anchor" href="#_8-xai-grok-build-cli网络流量分析-上传仓库全部文件及git历史" aria-label="Permalink to &quot;8. xAI Grok Build CLI网络流量分析：上传仓库全部文件及git历史&quot;">​</a></h4><p>分析显示，Grok Build编码CLI在用户登录后会上传三类数据：读取的文件内容以明文传输；整个仓库的全部文件内容及git历史独立于AI实际读取的文件上传至Google Cloud Storage，引发严重隐私担忧。</p><ul><li>来源：<a href="https://gist.github.com/cereblab/dc9a40bc26120f4540e4e09b75ffb547" target="_blank" rel="noreferrer">Hacker News</a></li></ul><h4 id="_9-开源模型面临未来6个月的生存考验" tabindex="-1">9. 开源模型面临未来6个月的生存考验 <a class="header-anchor" href="#_9-开源模型面临未来6个月的生存考验" aria-label="Permalink to &quot;9. 开源模型面临未来6个月的生存考验&quot;">​</a></h4><p>美国白宫正讨论通过新行政令管理开源模型，最可能在未来6个月内禁止或无限期延迟能力接近GPT 5.5、Claude Opus 4.8水平的开源权重模型发布。Anthropic主导的反中国模型政治运动以知识蒸馏为由推动监管。</p><ul><li>来源：<a href="https://www.interconnects.ai/p/6-months-to-live-for-open-models" target="_blank" rel="noreferrer">Interconnects</a></li></ul><hr><h2 id="小红书爆款-top-10" tabindex="-1">小红书爆款 TOP 10 <a class="header-anchor" href="#小红书爆款-top-10" aria-label="Permalink to &quot;小红书爆款 TOP 10&quot;">​</a></h2><p>数据日期：2026-07-11（注：热门笔记发布时间集中在2026-07-10）</p><table tabindex="0"><thead><tr><th>#</th><th>博主</th><th>互动量</th><th>粉丝</th><th>亮点</th></tr></thead><tbody><tr><td>1</td><td><strong>明理析法</strong></td><td>48w+</td><td>165粉</td><td>普法内容，素人爆款（互动/粉丝比极高）</td></tr><tr><td>2</td><td><strong>娱乐花无缺</strong></td><td>24w+</td><td>15w+</td><td>&quot;善良的人多了，就有了良田&quot; #快乐向前冲</td></tr><tr><td>3</td><td><strong>琼鬼娱乐</strong></td><td>23w+</td><td>15w+</td><td>俄罗斯艺术体操，阿纳斯塔西娅</td></tr><tr><td>4</td><td><strong>王建国是只猫</strong></td><td>22w+</td><td>3w+</td><td>猫咪表情&quot;小嘴巴不说话&quot;，萌宠</td></tr><tr><td>5</td><td><strong>梗图meme原创</strong></td><td>20w+</td><td>3w+</td><td>军事禁区禁止拍照meme，原创梗图</td></tr><tr><td>6</td><td><strong>饭匹兄弟</strong></td><td>19w+</td><td>94w+</td><td>小时候爱看的视频回忆杀</td></tr><tr><td>7</td><td><strong>菇噜噜</strong></td><td>17w+</td><td>23w+</td><td>猫狗日常+最适配BGM，宠物</td></tr><tr><td>8</td><td><strong>现在是昊宽</strong></td><td>17w+</td><td>28w+</td><td>认知提升&quot;价值重启EP1：钱如何运转&quot;</td></tr><tr><td>9</td><td><strong>游戏姬教主（活人版）</strong></td><td>14w+</td><td>7w+</td><td>飞行员考试&quot;挂科即死&quot;游戏内容</td></tr><tr><td>10</td><td><strong>佛系小詹设计日常</strong></td><td>13w+</td><td>76w+</td><td>PS设计教程，月薪三千抠投影</td></tr></tbody></table><p><strong>爆款分析：</strong></p><ul><li><strong>素人爆款</strong>：#1 明理析法仅165粉产出48w+互动，普法内容依然是小红书流量密码</li><li><strong>萌宠/搞笑</strong>：3席（猫、猫狗、萌宠），宠物赛道持续火爆</li><li><strong>知识教程</strong>：法律科普（#1）、设计教程（#10）、认知提升（#7）知识类内容多元</li><li><strong>娱乐/怀旧</strong>：童年回忆（#5）、体操（#2）、正能量故事（#2 #8）</li><li><strong>meme/抽象</strong>：原创梗图（#9）体现Z世代内容偏好</li></ul><hr><p><em>数据来源：AI HOT (<a href="https://aihot.virxact.com" target="_blank" rel="noreferrer">https://aihot.virxact.com</a>) · 小红书红狐API</em><em>生成时间：2026-07-13 17:00 BJT</em></p>',46)])])}const g=a(d,[["render",l]]);export{c as __pageData,g as default};
